package git

import (
	"fmt"
	"net/url"
	"os"
	"testing"

	"github.com/google/uuid"
	"github.com/stretchr/testify/require"
)

func TestRepo(t *testing.T) {
	testServer, testRepoURL, testRepoCreds := setupRemoteRepo(t)
	defer testServer.Close()

	rep, err := Clone(
		testRepoURL,
		&ClientOptions{
			Credentials: &testRepoCreds,
		},
		nil,
	)
	require.NoError(t, err)
	require.NotNil(t, rep)
	defer rep.Close()
	r, ok := rep.(*repo)
	require.True(t, ok)

	t.Run("can clone", func(t *testing.T) {
		require.Equal(t, testRepoURL, r.originalURL)
		var accessURL *url.URL
		accessURL, err = url.Parse(r.accessURL)
		require.NoError(t, err)
		accessURL.User = nil
		require.Equal(t, testRepoURL, accessURL.String())
		require.NotEmpty(t, r.homeDir)
		var fi os.FileInfo
		fi, err = os.Stat(r.homeDir)
		require.NoError(t, err)
		require.True(t, fi.IsDir())
		require.NotEmpty(t, r.dir)
		fi, err = os.Stat(r.dir)
		require.NoError(t, err)
		require.True(t, fi.IsDir())
	})

	t.Run("can get the repo url", func(t *testing.T) {
		require.Equal(t, r.originalURL, r.URL())
	})

	t.Run("can get the home dir", func(t *testing.T) {
		require.Equal(t, r.homeDir, r.HomeDir())
	})

	t.Run("can get the working tree dir", func(t *testing.T) {
		require.Equal(t, r.dir, r.Dir())
	})

	t.Run("can check for diffs -- negative result", func(t *testing.T) {
		var hasDiffs bool
		hasDiffs, err = rep.HasDiffs()
		require.NoError(t, err)
		require.False(t, hasDiffs)
	})

	err = os.WriteFile(fmt.Sprintf("%s/%s", rep.Dir(), "test.txt"), []byte("foo"), 0600)
	require.NoError(t, err)

	t.Run("can check for diffs -- positive result", func(t *testing.T) {
		var hasDiffs bool
		hasDiffs, err = rep.HasDiffs()
		require.NoError(t, err)
		require.True(t, hasDiffs)
	})

	testCommitMessage := fmt.Sprintf(`test commit %s

with a body
`, uuid.NewString())
	err = rep.AddAllAndCommit(testCommitMessage, nil)
	require.NoError(t, err)

	t.Run("can commit", func(t *testing.T) {
		require.NoError(t, err)
	})

	lastCommitID, err := rep.LastCommitID()
	require.NoError(t, err)

	t.Run("can get last commit id", func(t *testing.T) {
		require.NoError(t, err)
		require.NotEmpty(t, lastCommitID)
	})

	t.Run("can get commit message by id", func(t *testing.T) {
		var msg string
		msg, err = rep.CommitMessage(lastCommitID)
		require.NoError(t, err)
		require.Equal(t, testCommitMessage, msg)
	})

	t.Run("can get diff paths", func(t *testing.T) {
		var paths []string
		paths, err = rep.GetDiffPathsForCommitID(lastCommitID)
		require.NoError(t, err)
		require.Len(t, paths, 1)
	})

	t.Run("can check if remote branch exists -- negative result", func(t *testing.T) {
		var exists bool
		exists, err = rep.RemoteBranchExists("main") // The remote repo is empty!
		require.NoError(t, err)
		require.False(t, exists)
	})

	err = rep.Push(nil)
	require.NoError(t, err)

	t.Run("can push", func(t *testing.T) {
		require.NoError(t, err)
	})

	t.Run("can check if remote branch exists -- positive result", func(t *testing.T) {
		var exists bool
		exists, err = rep.RemoteBranchExists("main")
		require.NoError(t, err)
		require.True(t, exists)
	})

	testBranch := fmt.Sprintf("test-branch-%s", uuid.NewString())
	err = rep.CreateChildBranch(testBranch)
	require.NoError(t, err)

	t.Run("can create a child branch", func(t *testing.T) {
		require.NoError(t, err)
	})

	err = os.WriteFile(fmt.Sprintf("%s/%s", rep.Dir(), "test.txt"), []byte("bar"), 0600)
	require.NoError(t, err)

	t.Run("can hard reset", func(t *testing.T) {
		var hasDiffs bool
		hasDiffs, err = rep.HasDiffs()
		require.NoError(t, err)
		require.True(t, hasDiffs)
		err = rep.ResetHard()
		require.NoError(t, err)
		hasDiffs, err = rep.HasDiffs()
		require.NoError(t, err)
		require.False(t, hasDiffs)
	})

	t.Run("can create an orphaned branch", func(t *testing.T) {
		testBranch := fmt.Sprintf("test-branch-%s", uuid.NewString())
		err = rep.CreateOrphanedBranch(testBranch)
		require.NoError(t, err)
	})

	t.Run("can load an existing repo", func(t *testing.T) {
		existingRepo, err := LoadRepo(
			rep.Dir(),
			&LoadRepoOptions{
				Credentials: &testRepoCreds,
			},
		)
		require.NoError(t, err)
		require.Equal(t, rep, existingRepo)
	})

	t.Run("can close repo", func(t *testing.T) {
		require.NoError(t, rep.Close())
		_, err := os.Stat(r.HomeDir())
		require.Error(t, err)
		require.True(t, os.IsNotExist(err))
	})

}

package git

import (
	"fmt"
	"net/http/httptest"
	"os"
	"path/filepath"
	"testing"

	"github.com/google/uuid"
	"github.com/sosedoff/gitkit"
	"github.com/stretchr/testify/require"

	libExec "github.com/akuity/kargo/pkg/exec"
	"github.com/akuity/kargo/pkg/types"
)

// setupRemoteRepo creates a gitkit-backed remote repository accessible via an
// http server, returning the server, repo URL, and credentials, if applicable.
// The caller must close the server when done with it.
func setupRemoteRepo(
	t *testing.T,
	initFns ...func(t *testing.T, repo WorkTree),
) (*httptest.Server, string, RepoCredentials) {
	t.Helper()

	creds := RepoCredentials{
		Username: "test-user",
		Password: "test-pass",
	}

	var useAuth bool
	if s := os.Getenv("TEST_GIT_CLIENT_WITH_AUTH"); s != "" {
		useAuth = types.MustParseBool(s)
	}
	service := gitkit.New(gitkit.Config{
		Dir:        t.TempDir(),
		AutoCreate: true,
		Auth:       useAuth,
	})
	require.NoError(t, service.Setup())
	service.AuthFunc = func(
		c gitkit.Credential, _ *gitkit.Request,
	) (bool, error) {
		return c.Username == creds.Username &&
			c.Password == creds.Password, nil
	}
	server := httptest.NewServer(service)
	// server must be closed by the caller

	testRepoURL := fmt.Sprintf("%s/test.git", server.URL)

	repo, err := Clone(testRepoURL, &ClientOptions{Credentials: &creds}, nil)
	require.NoError(t, err)
	require.NotNil(t, repo)
	defer repo.Close()

	for _, initFn := range initFns {
		initFn(t, repo)
	}

	return server, testRepoURL, creds
}

func initialMainCommit(t *testing.T, rep WorkTree) {
	err := os.WriteFile(
		fmt.Sprintf("%s/%s", rep.Dir(), "test.txt"),
		[]byte("foo"),
		0600,
	)
	require.NoError(t, err)
	err = rep.AddAllAndCommit(fmt.Sprintf("initial commit %s", uuid.NewString()), nil)
	require.NoError(t, err)
	err = rep.Push(nil)
	require.NoError(t, err)
}

func commitAhead(t *testing.T, rep WorkTree) {
	err := os.WriteFile(
		fmt.Sprintf("%s/remote.txt", rep.Dir()),
		[]byte("from-remote"),
		0o600,
	)
	require.NoError(t, err)
	err = rep.AddAllAndCommit("remote commit", nil)
	require.NoError(t, err)
	err = rep.Push(&PushOptions{TargetBranch: "ahead"})
	require.NoError(t, err)
}

// internalWorkTree extracts the unexported *workTree from a Repo so tests
// can call unexported methods.
func internalWorkTree(t *testing.T, r Repo) *workTree {
	t.Helper()
	rr, ok := r.(*repo)
	require.True(t, ok, "expected *repo, got %T", r)
	return rr.workTree
}

// enableFakeCommitSigning installs a fake GPG program into the work tree's home
// directory and configures git to use it. The script handles both signing
// and verification. When trusted is true, verification reports
// TRUST_ULTIMATE (git %G? = G). When false, verification reports
// TRUST_UNDEFINED (git %G? = U).
func enableFakeCommitSigning(t *testing.T, wt *workTree, trusted bool) {
	t.Helper()
	trustLine := "echo '[GNUPG:] TRUST_UNDEFINED'"
	if trusted {
		trustLine = "echo '[GNUPG:] TRUST_ULTIMATE'"
	}
	// The script inspects its arguments to distinguish signing from
	// verification. Git passes --verify when checking a signature and
	// -bsau when creating one. The signing output must be a valid PGP
	// armor block; git validates the format before calling GPG to verify.
	script := fmt.Sprintf(
		"#!/bin/sh\n"+
			"verify=0\n"+
			"for arg in \"$@\"; do\n"+
			"  case \"$arg\" in --verify) verify=1 ;; esac\n"+
			"done\n"+
			"if [ \"$verify\" = 1 ]; then\n"+
			"  echo '[GNUPG:] GOODSIG ABCDEF1234567890 Test User'\n"+
			"  %s\n"+
			"else\n"+
			"  cat >/dev/null\n"+
			"  echo '' >&2\n"+
			"  echo '[GNUPG:] SIG_CREATED D 1 2 00 0 ABCDEF' >&2\n"+
			"  echo '-----BEGIN PGP SIGNATURE-----'\n"+
			"  echo ''\n"+
			"  echo 'iQEzBAABCAAdFiEEfake'\n"+
			"  echo '=fake'\n"+
			"  echo '-----END PGP SIGNATURE-----'\n"+
			"fi\n",
		trustLine,
	)
	fakeGPG := filepath.Join(wt.HomeDir(), "fake-gpg")
	err := os.WriteFile(fakeGPG, []byte(script), 0o755)
	require.NoError(t, err)
	_, err = libExec.Exec(wt.buildGitCommand(
		"config", "--global", "gpg.program", fakeGPG,
	))
	require.NoError(t, err)
	_, err = libExec.Exec(wt.buildGitCommand(
		"config", "--global", "commit.gpgSign", "true",
	))
	require.NoError(t, err)
}

// disableFakeCommitSigning turns off commit.gpgSign in the work tree's global
// git config.
func disableFakeCommitSigning(t *testing.T, wt *workTree) {
	t.Helper()
	_, err := libExec.Exec(wt.buildGitCommand(
		"config", "--unset", "--global", "commit.gpgSign",
	))
	require.NoError(t, err)
	_, err = libExec.Exec(wt.buildGitCommand(
		"config", "--global", "commit.gpgSign", "false",
	))
	require.NoError(t, err)
}

